Patch Set 16:

> So tell me what is the different between passing around a bool to
 > inquiring if it locked using inode_is_locked() ?  I kind of did
 > that before. So instead you want something in osd_object_spec_find()
 > like:
 > 
 > bool magic_bool = inode_is_locked(root->d_inode);
 > 
 > if (!magic_bool) {
 > dentry = osd_ios_lookup_one_len_unlocked(name, root,
 > strlen(name));
 > } else {
 > dentry = osd_ios_lookup_one_len(name, root, strlen(name));
 > 
 > Which you disliked before.

My suggestion is not to add "if/else" checks throughout the functions, but rather:

 struct dentry *osd_lookup_one_len_common(..., bool lock_parent)
 {
        struct dentry *dchild;

        if (lock_parent)
                inode_lock(base);
        dchild = lookup_one_len(name, base, namelen);
        if (lock_parent)
                inode_unlock(base);

        if (IS_ERR(dchild) || !dchild->d_inode)
                return dchild;

        if (is_bad_inode(dchild->d_inode)) {
                CERROR("bad inode returned %lu/%u\n",
                       dchild->d_inode->i_ino, dchild->d_inode->i_generation);
                dput(dchild);
                dchild = ERR_PTR(-ENOENT);
        }

        return dchild;
 }

 static inline int osd_lookup_one_len_unlocked(...)
 {
        return osd_lookup_one_len_common(..., true);
 }

 static inline struct dentry *osd_lookup_one_len(...)
 {
        struct dentry *dchild;

        dchild = osd_lookup_one_len_common(..., false);

        /* I don't know if we need this error message, but keep it for continuity */
        if (IS_ERR(dchild)) {
                if (PTR_ERR(dchild) != -ENOENT)
                        CERROR("Fail to find %.*s in %.*s (%lu/%u): rc = %d\n",
                               namelen, name, parent->d_name.len,
                               parent->d_name.name, parent->d_inode->i_ino,
                               parent->d_inode->i_generation, rc);

                return dchild;
        }

        if (dchild->d_inode == NULL) {
                dput(dchild);
                return ERR_PTR(-ENOENT);
        }

        return dchild;
 }

and then call one of the two wrapper functions in _most_ of the code, but there is only one implementation of the core functionality.  Unfortunately, we can't do the inode_lock/unlock() in the _unlocked() wrapper itself, since the _common() part needs to be called from other functions and handle the locking itself, as shown below.

The big benefit is elsewhere, to avoid duplicating large functions, like:

 int osd_obj_spec_lookup_common(..., bool lock_parent)
 {
        :
        dentry = osd_lookup_one_len_common(..., lock_parent);
        :
 }

 int osd_oi_lookup_common(..., bool lock_parent)
 {
        if (unlikely(fid_is_last_id(fid)))
               return osd_obj_spec_lookup_common(..., lock_parent);
        :
               if (rc == -ENOENT)
                       return osd_obj_spec_lookup_common(..., lock_parent);
               return rc;
        :
 }

 static inline int osd_oi_lookup(...)
 {
        return osd_oi_lookup_common(..., false);
 }

 static inline int osd_oi_lookup_unlocked(...)
 {
        return osd_oi_lookup_common(..., true);
 }

This allows the body of these other functions to be shared, and they doesn't care whether the bottom level is doing the locking or not, since lock_parent is passed through in either case, but in the rest of the code it can still use the "normal" or "_unlocked()" variant as needed for cleanliness.  No need for if/else blocks everywhere, nor any need for code duplication.
